-- ============================================
-- Legislacao full-site: haddad-gov-sp / Prefeitura de Sao Paulo / legislacao_mandato_executivo
-- Completo provado escopado: leis municipais PMSP assinadas/promulgadas por Fernando Haddad
-- Generated by scripts/generate-legislacao-haddad-sp-prefeitura-completo-20260512.ts
-- Artifact: fonte interna de curadoria
-- ============================================
-- Fonte oficial: Prefeitura de Sao Paulo - Catalogo de Legislacao Municipal
-- Busca POST /busca e /busca/pg/N:
--   ano-inicial=01/01/2013
--   ano-final=31/12/2016
--   tipo[]=LEI
--
-- Coverage:
--   coverage_id    = haddad-sp-prefeitura-completo-leis-municipais-2013-2016-cutoff-20260512
--   coverage_scope = inventario_completo_sp_prefeitura_leis_municipais_fernando_haddad_2013_2016_cutoff_20260512
--
-- Filtro factual: paginas oficiais PMSP com numero, data, ementa,
-- formula "FERNANDO HADDAD, Prefeito do Municipio de Sao Paulo" e
-- "decretou e eu promulgo a seguinte lei".
-- Nao e inventario global da vida politica, nao cobre atos fora do Catalogo
-- PMSP, nao cobre decretos/portarias e nao toca autoria parlamentar.
--
-- Esta migration escreve somente em legislacao_mandato_executivo.
-- Esta migration NAO escreve em projetos_lei.
-- Esta migration NAO altera historico_politico.
-- ============================================

DO $$
DECLARE
  cand_id uuid;
  lme_total int;
  target_count int;
  old_count int;
  other_lme_count int;
  mandato_count int;
  projetos_count int;
BEGIN
  SELECT id INTO cand_id FROM candidatos WHERE slug = 'haddad-gov-sp';

  IF cand_id IS NULL THEN
    RAISE NOTICE 'haddad-gov-sp: candidato ausente neste banco local/CI minimo; seed LME PMSP pulado';
    RETURN;
  END IF;

  SELECT count(*) INTO lme_total
  FROM legislacao_mandato_executivo
  WHERE candidato_id = cand_id;

  SELECT count(*) INTO target_count
  FROM legislacao_mandato_executivo
  WHERE candidato_id = cand_id
    AND metadata->>'coverage_id' = 'haddad-sp-prefeitura-completo-leis-municipais-2013-2016-cutoff-20260512';

  SELECT count(*) INTO old_count
  FROM legislacao_mandato_executivo
  WHERE candidato_id = cand_id
    AND metadata->>'coverage_id' = 'haddad-sp-prefeitura-leis-ampliado-parcial-lote-a-20260507';

  SELECT count(*) INTO other_lme_count
  FROM legislacao_mandato_executivo
  WHERE candidato_id = cand_id
    AND COALESCE(metadata->>'coverage_id', '') NOT IN ('haddad-sp-prefeitura-completo-leis-municipais-2013-2016-cutoff-20260512', 'haddad-sp-prefeitura-leis-ampliado-parcial-lote-a-20260507');

  IF NOT (
    (lme_total = 0 AND target_count = 0 AND old_count = 0)
    OR (lme_total = 5 AND target_count = 0 AND old_count = 5)
    OR (lme_total = 602 AND target_count = 602 AND old_count = 0)
  ) THEN
    RAISE EXCEPTION 'Pre-condicao haddad-gov-sp: LME deve estar vazia, com 5 rows antigas do lote A ou com 602 rows alvo idempotentes; total=%, target=%, old=%', lme_total, target_count, old_count;
  END IF;

  IF other_lme_count <> 0 THEN
    RAISE EXCEPTION 'Pre-condicao haddad-gov-sp: % rows LME fora do coverage antigo/alvo; abortando para nao misturar lotes', other_lme_count;
  END IF;

  SELECT count(*) INTO projetos_count
  FROM projetos_lei
  WHERE candidato_id = cand_id;

  IF projetos_count <> 0 THEN
    RAISE EXCEPTION 'Pre-condicao haddad-gov-sp: projetos_lei mudou de 0 para %', projetos_count;
  END IF;

  SELECT count(*) INTO mandato_count
  FROM historico_politico hp
  WHERE hp.candidato_id = cand_id
    AND COALESCE(hp.tipo_evento, 'mandato') = 'mandato'
    AND (hp.cargo ILIKE '%Prefeito%' OR hp.cargo_canonico = 'Prefeito')
    AND UPPER(COALESCE(hp.estado, '')) = 'SP'
    AND (hp.cargo ILIKE '%São Paulo%' OR hp.cargo ILIKE '%Sao Paulo%' OR hp.observacoes ILIKE '%Prefeitura de São Paulo%' OR hp.observacoes ILIKE '%Prefeitura de Sao Paulo%')
    AND COALESCE(hp.periodo_inicio, 9999) <= 2016
    AND COALESCE(hp.periodo_fim, 9999) >= 2013;

  IF mandato_count < 1 THEN
    RAISE EXCEPTION 'Pre-condicao haddad-gov-sp: mandato Prefeito/Sao Paulo compativel com 2013-2016 nao encontrado em historico_politico';
  END IF;
END $$;

