DO $$
DECLARE
  seed_count int;
  duplicate_seed_count int;
BEGIN
  SELECT count(*) INTO seed_count FROM _seed_haddad_sp_prefeitura_completo_lme;
  SELECT count(*) INTO duplicate_seed_count
  FROM (
    SELECT identificador_fonte
    FROM _seed_haddad_sp_prefeitura_completo_lme
    GROUP BY identificador_fonte
    HAVING count(*) > 1
  ) duplicated;

  IF seed_count <> 602 THEN
    RAISE EXCEPTION 'Pre-condicao haddad-gov-sp: seed tem % rows, esperado 602', seed_count;
  END IF;

  IF duplicate_seed_count <> 0 THEN
    RAISE EXCEPTION 'Pre-condicao haddad-gov-sp: seed tem % identificadores duplicados', duplicate_seed_count;
  END IF;
END $$;

CREATE TEMP TABLE _target_haddad_sp_prefeitura_completo_lme ON COMMIT DROP AS
SELECT
  c.id AS candidato_id,
  seed.*,
  (
    SELECT hp.id
    FROM historico_politico hp
    WHERE hp.candidato_id = c.id
      AND COALESCE(hp.tipo_evento, 'mandato') = 'mandato'
      AND (hp.cargo ILIKE '%Prefeito%' OR hp.cargo_canonico = 'Prefeito')
      AND UPPER(COALESCE(hp.estado, '')) = 'SP'
      AND (hp.cargo ILIKE '%São Paulo%' OR hp.cargo ILIKE '%Sao Paulo%' OR hp.observacoes ILIKE '%Prefeitura de São Paulo%' OR hp.observacoes ILIKE '%Prefeitura de Sao Paulo%')
      AND COALESCE(hp.periodo_inicio, 9999) <= seed.ano
      AND COALESCE(hp.periodo_fim, 9999) >= seed.ano
    ORDER BY hp.periodo_inicio DESC NULLS LAST, hp.id
    LIMIT 1
  ) AS historico_politico_id
FROM candidatos c
CROSS JOIN _seed_haddad_sp_prefeitura_completo_lme seed
WHERE c.slug = 'haddad-gov-sp';

UPDATE legislacao_mandato_executivo lme
SET
  historico_politico_id = target.historico_politico_id,
  tipo_relacao = target.tipo_relacao,
  esfera = target.esfera,
  uf_norma = target.uf_norma,
  municipio_norma = target.municipio_norma,
  tipo_norma = target.tipo_norma,
  numero = target.numero,
  ano = target.ano,
  data_norma = target.data_norma::date,
  ementa = target.ementa,
  signatario = target.signatario,
  autoridade_papel = target.autoridade_papel,
  fonte_primaria_url = target.fonte_primaria_url,
  fonte_primaria_titulo = target.fonte_primaria_titulo,
  fonte_tramitacao_url = target.fonte_tramitacao_url,
  metadata = target.metadata
FROM _target_haddad_sp_prefeitura_completo_lme target
WHERE lme.candidato_id = target.candidato_id
  AND lme.identificador_fonte = target.identificador_fonte;

INSERT INTO legislacao_mandato_executivo (
  candidato_id,
  historico_politico_id,
  tipo_relacao,
  esfera,
  uf_norma,
  municipio_norma,
  tipo_norma,
  numero,
  ano,
  data_norma,
  ementa,
  signatario,
  autoridade_papel,
  fonte_primaria_url,
  fonte_primaria_titulo,
  fonte_tramitacao_url,
  identificador_fonte,
  metadata
)
SELECT
  target.candidato_id,
  target.historico_politico_id,
  target.tipo_relacao,
  target.esfera,
  target.uf_norma,
  target.municipio_norma,
  target.tipo_norma,
  target.numero,
  target.ano,
  target.data_norma::date,
  target.ementa,
  target.signatario,
  target.autoridade_papel,
  target.fonte_primaria_url,
  target.fonte_primaria_titulo,
  target.fonte_tramitacao_url,
  target.identificador_fonte,
  target.metadata
FROM _target_haddad_sp_prefeitura_completo_lme target
WHERE NOT EXISTS (
    SELECT 1
    FROM legislacao_mandato_executivo lme
    WHERE lme.candidato_id = target.candidato_id
      AND lme.identificador_fonte = target.identificador_fonte
  );

DO $$
DECLARE
  cand_id uuid;
  total_count int;
  scope_count int;
  metadata_count int;
  projetos_count int;
  missing_mandate_count int;
  old_count int;
BEGIN
  SELECT id INTO cand_id FROM candidatos WHERE slug = 'haddad-gov-sp';

  IF cand_id IS NULL THEN
    RAISE NOTICE 'haddad-gov-sp: pos-condicao pulada porque candidato nao existe neste banco local/CI minimo';
    RETURN;
  END IF;

  SELECT count(*) INTO total_count
  FROM legislacao_mandato_executivo
  WHERE candidato_id = cand_id;

  SELECT count(*) INTO scope_count
  FROM legislacao_mandato_executivo
  WHERE candidato_id = cand_id
    AND metadata->>'coverage_id' = 'haddad-sp-prefeitura-completo-leis-municipais-2013-2016-cutoff-20260512'
    AND metadata->>'coverage_scope' = 'inventario_completo_sp_prefeitura_leis_municipais_fernando_haddad_2013_2016_cutoff_20260512'
    AND signatario = 'FERNANDO HADDAD'
    AND autoridade_papel = 'titular';

  SELECT count(*) INTO metadata_count
  FROM legislacao_mandato_executivo
  WHERE candidato_id = cand_id
    AND metadata->>'coverage_id' = 'haddad-sp-prefeitura-completo-leis-municipais-2013-2016-cutoff-20260512'
    AND metadata->>'coverage_scope' = 'inventario_completo_sp_prefeitura_leis_municipais_fernando_haddad_2013_2016_cutoff_20260512'
    AND metadata->>'coverage_status' = 'completo_escopado'
    AND metadata->>'coverage_public_status' = 'executive_complete'
    AND metadata->>'tabela_alvo' = 'legislacao_mandato_executivo'
    AND metadata->>'projetos_lei_mixed' = 'false';

  SELECT count(*) INTO missing_mandate_count
  FROM legislacao_mandato_executivo
  WHERE candidato_id = cand_id
    AND metadata->>'coverage_id' = 'haddad-sp-prefeitura-completo-leis-municipais-2013-2016-cutoff-20260512'
    AND historico_politico_id IS NULL;

  SELECT count(*) INTO old_count
  FROM legislacao_mandato_executivo
  WHERE candidato_id = cand_id
    AND metadata->>'coverage_id' = 'haddad-sp-prefeitura-leis-ampliado-parcial-lote-a-20260507';

  SELECT count(*) INTO projetos_count
  FROM projetos_lei
  WHERE candidato_id = cand_id;

  IF total_count <> 602 THEN
    RAISE EXCEPTION 'Pos-apply haddad-gov-sp: total LME esperado 602, encontrado %', total_count;
  END IF;

  IF scope_count <> 602 THEN
    RAISE EXCEPTION 'Pos-apply haddad-gov-sp: esperadas 602 rows com coverage_id/scope/signatario alvo, encontradas %', scope_count;
  END IF;

  IF metadata_count <> 602 THEN
    RAISE EXCEPTION 'Pos-apply haddad-gov-sp: esperadas 602 rows com metadata completo_escopado, encontradas %', metadata_count;
  END IF;

  IF missing_mandate_count <> 0 THEN
    RAISE EXCEPTION 'Pos-apply haddad-gov-sp: % rows ficaram sem historico_politico_id, esperado 0 pelo historico_politico remoto atual', missing_mandate_count;
  END IF;

  IF old_count <> 0 THEN
    RAISE EXCEPTION 'Pos-apply haddad-gov-sp: coverage antigo ainda tem % rows; esperado 0 apos promocao completa', old_count;
  END IF;

  IF projetos_count <> 0 THEN
    RAISE EXCEPTION 'Pos-apply haddad-gov-sp: projetos_lei mudou de 0 para %', projetos_count;
  END IF;

  RAISE NOTICE 'Pos-apply haddad-gov-sp PMSP completo: legislacao_mandato_executivo=% coverage_scope=% projetos_lei_preservado=%', total_count, scope_count, projetos_count;
END $$;
